window.QUESTIONS_RAW = [{"s":1,"q":"Which type of OSPFv2 packet is used to forward OSPF link change information?","o":["link-state acknowledgment","link-state update","hello","database description"],"a":[1],"src":"Questions 1-50","si":1},{"s":2,"q":"What protocol synchronizes with a private master clock or with a publicly available server on the internet?","o":["MPLS","CBWFQ","TFTP","NTP"],"a":[3],"src":"Questions 1-50","si":2},{"s":3,"q":"Which type of VPN allows multicast and broadcast traffic over a secure site-to-site VPN?","o":["dynamic multipoint VPN","SSL VPN","IPsec virtual tunnel interface","GRE over IPsec"],"a":[0],"src":"Questions 1-50","si":3},{"s":4,"q":"An OSPF router has three directly connected networks; 10.0.0.0/16, 10.1.0.0/16, and 10.2.0.0/16. Which OSPF network command would advertise only the 10.1.0.0 network to neighbors?","o":["router(config-router)# network 10.1.0.0 0.0.255.255 area 0","router(config-router)# network 10.1.0.0 0.0.15.255 area 0","router(config-router)# network 10.1.0.0 255.255.255.0 area 0","router(config-router)# network 10.1.0.0 0.0.0.0 area 0"],"a":[0],"src":"Questions 1-50","si":4},{"s":5,"q":"Refer to the exhibit. Which sequence of commands should be used to configure router A for OSPF?","o":["router ospf 1\nnetwork 192.168.10.0 area 0","router ospf 1\nnetwork 192.168.10.0","router ospf 1\nnetwork 192.168.10.64 255.255.255.192\nnetwork 192.168.10.192 255.255.255.252","router ospf 1\nnetwork 192.168.10.64 0.0.0.63 area 0\nnetwork 192.168.10.192 0.0.0.3 area 0"],"a":[3],"src":"Questions 1-50","si":5,"e":1},{"s":6,"q":"An administrator is configuring single-area OSPF on a router. One of the networks that must be advertised is 172.20.0.0 255.255.252.0. What wildcard mask would the administrator use in the OSPF network statement?","o":["0.0.15.255","0.0.3.255","0.0.7.255","0.0.1.255"],"a":[1],"src":"Questions 1-50","si":6},{"s":7,"q":"How does virtualization help with disaster recovery within a data center?","o":["improvement of business practices","supply of consistent air flow","support of live migration","guarantee of power","Less energy is consumed.","Server provisioning is faster.","Hardware at the recovery site does not have to be identical to production equipment.","Power is always provided."],"a":[2,6],"m":true,"src":"Questions 1-50","si":7},{"s":8,"q":"How does virtualization help with disaster recovery within a data center?","o":["Hardware at the recovery site does not have to be identical to production equipment.","Power is always provided.","Less energy is consumed.","Server provisioning is faster."],"a":[0],"src":"Questions 1-50","si":8},{"s":9,"q":"Refer to the exhibit. Which devices exist in the failure domain when switch S3 loses power?","o":["S4 and PC_2","PC_3 and AP_2","AP_2 and AP_1","PC_3 and PC_2","S1 and S4"],"a":[1],"src":"Questions 1-50","si":9,"e":1},{"s":10,"q":"Which set of access control entries would allow all users on the 192.168.10.0/24 network to access a web server that is located at 172.17.80.1, but would not allow them to use Telnet?","o":["access-list 103 deny tcp host 192.168.10.0 any eq 23\naccess-list 103 permit tcp host 192.168.10.1 eq 80","access-list 103 permit tcp 192.168.10.0 0.0.0.255 host 172.17.80.1 eq 80\naccess-list 103 deny tcp 192.168.10.0 0.0.0.255 any eq 23","access-list 103 permit tcp 192.168.10.0 0.0.0.255 any eq 80\naccess-list 103 deny tcp 192.168.10.0 0.0.0.255 any eq 23","access-list 103 permit 192.168.10.0 0.0.0.255 host 172.17.80.1\naccess-list 103 deny tcp 192.168.10.0 0.0.0.255 any eq telnet"],"a":[1],"src":"Questions 1-50","si":10},{"s":11,"q":"Refer to the exhibit. A network administrator needs to add an ACE to the TRAFFIC-CONTROL ACL that will deny IP traffic from the subnet 172.23.16.0/20. Which ACE will meet this requirement?","o":["5 deny 172.23.16.0 0.0.15.255","5 deny 172.23.16.0 0.0.255.255","15 deny 172.23.16.0 0.0.15.255","30 deny 172.23.16.0 0.0.15.255"],"a":[0],"src":"Questions 1-50","si":11,"e":1},{"s":12,"q":"Which step in the link-state routing process is described by a router building a link-state database based on received LSAs?","o":["executing the SPF algorithm","building the topology table","selecting the router ID","declaring a neighbor to be inaccessible"],"a":[1],"src":"Questions 1-50","si":12},{"s":13,"q":"What protocol uses agents, that reside on managed devices, to collect and store information about the device and its operation?","o":["SYSLOG","TFTP","CBWFQ","SNMP"],"a":[3],"src":"Questions 1-50","si":13},{"s":14,"q":"An administrator is configuring single-area OSPF on a router. One of the networks that must be advertised is 10.27.27.0 255.255.255.0. What wildcard mask would the administrator use in the OSPF network statement?","o":["0.0.0.63","0.0.0.255","0.0.0.31","0.0.0.15"],"a":[1],"src":"Questions 1-50","si":14},{"s":15,"q":"When will an OSPF-enabled router transition from the Down state to the Init state?","o":["when an OSPF-enabled interface becomes active","as soon as the router starts","when the router receives a hello packet from a neighbor router","as soon as the DR/BDR election process is complete"],"a":[0],"src":"Questions 1-50","si":15},{"s":16,"q":"What type of traffic is described as having a high volume of data per packet?","o":["data","video","voice"],"a":[1],"src":"Questions 1-50","si":16},{"s":17,"q":"What protocol is a vendor-neutral Layer 2 protocol that advertises the identity and capabilities of the host device to other connected network devices?","o":["LLDP","NTP","TFTP","SNMP"],"a":[0],"src":"Questions 1-50","si":17},{"s":18,"q":"Which step in the link-state routing process is described by a router running an algorithm to determine the best path to each destination?","o":["building the topology table","selecting the router ID","declaring a neighbor to be inaccessible","executing the SPF algorithm"],"a":[3],"src":"Questions 1-50","si":18},{"s":19,"q":"Refer to the exhibit. Which conclusion can be drawn from this OSPF multiaccess network?","o":["If the DR stops producing Hello packets, a BDR will be elected, and then it promotes itself to assume the role of DR.","With an election of the DR, the number of adjacencies is reduced from 6 to 3.","When a DR is elected all other non-DR routers become DROTHER.","All DROTHER routers will send LSAs to the DR and BDR to multicast 224.0.0.5."],"a":[1],"src":"Questions 1-50","si":19,"e":1},{"s":20,"q":"Refer to the exhibit. The network administrator has an IP address of 192.168.11.10 and needs access to manage R1. What is the best ACL type and placement to use in this situation?","o":["extended ACL outbound on R2 WAN interface towards the internet","standard ACL inbound on R1 vty lines","extended ACLs inbound on R1 G0/0 and G0/1","extended ACL outbound on R2 S0/0/1"],"a":[1],"src":"Questions 1-50","si":20,"e":1},{"s":21,"q":"Which type of VPN connects using the Transport Layer Security (TLS) feature?","o":["SSL VPN","IPsec virtual tunnel interface","GRE over IPsec","dynamic multipoint VPN"],"a":[0],"src":"Questions 1-50","si":21},{"s":22,"q":"Which group of APIs are used by an SDN controller to communicate with various applications?","o":["eastbound APIs","westbound APIs","northbound APIs","southbound APIs"],"a":[2],"src":"Questions 1-50","si":22},{"s":23,"q":"A company has consolidated a number of servers and it is looking for a program or firmware to create and control virtual machines which have access to all the hardware of the consolidated servers. What service or technology would support this requirement?","o":["Cisco ACI","software defined networking","Type-1 hypervisor","APIC-EM"],"a":[2],"src":"Questions 1-50","si":23},{"s":24,"q":"What command would be used as part of configuring NAT or PAT to identify inside local addresses that are to be translated?","o":["ip nat inside source list 24 interface serial 0/1/0 overload","ip nat inside source list 14 pool POOL-STAT overload","access-list 10 permit 172.19.89.0 0.0.0.255","ip nat inside source list ACCTNG pool POOL-STAT"],"a":[2],"src":"Questions 1-50","si":24},{"s":25,"q":"What command would be used as part of configuring NAT or PAT to identify inside local addresses that are to be translated?","o":["ip nat inside source list 24 interface serial 0/1/0 overload","ip nat inside source list 14 pool POOL-STAT overload","access-list 10 permit 172.19.89.0 0.0.0.255","ip nat inside source list ACCTNG pool POOL-STAT"],"a":[2],"src":"Questions 1-50","si":25},{"s":26,"q":"Anycompany has decided to reduce its environmental footprint by reducing energy costs, moving to a smaller facility, and promoting telecommuting, what service or technology would support requirement?","o":["Cloud services","Data center","APIC-EM","Cisco ACI"],"a":[0],"src":"Questions 1-50","si":26},{"s":27,"q":"Refer to the exhibit. An administrator is trying to back up the current running configuration of the router to a USB drive, and enters the command copy usbflash0:/R1-config running-config on the router command line. After removing the USB drive and connecting it to a PC, the administrator discovers that the running configuration was not properly backed up to the R1-config file. What is the problem?","o":["The file already exists on the USB drive and cannot be overwritten.","The drive was not properly formatted with the FAT16 file system.","There is no space left on the USB drive.","The USB drive is not recognized by the router.","The command that the administrator used was incorrect."],"a":[4],"src":"Questions 1-50","si":27,"e":1},{"s":28,"q":"Which three types of VPNs are examples of enterprise-managed site-to-site VPNs? (Choose three.)","o":["Layer 3 MPLS VPN","IPsec VPN","Cisco Dynamic Multipoint VPN","GRE over IPsec VPN","clientless SSL VPN","client-based IPsec VPN"],"a":[1,2,3],"m":true,"src":"Questions 1-50","si":28},{"s":29,"q":"Refer to the exhibit. Employees on 192.168.11.0/24 work on critically sensitive information and are not allowed access off their network. What is the best ACL type and placement to use in this situation?","o":["standard ACL inbound on R1 vty lines","extended ACL inbound on R1 G0/0","standard ACL inbound on R1 G0/1","extended ACL inbound on R3 S0/0/1"],"a":[2],"src":"Questions 1-50","si":29,"e":1},{"s":30,"q":"In an OSPF network which two statements describe the link-state database (LSDB)? (Choose two.)","o":["It can be viewed by using the show ip ospf database command.","A neighbor table is created based on the LSDB.","It contains a list of only the best routes to a particular network.","It contains a list of all neighbor routers to which a router has established bidirectional communication.","All routers within an area have an identical link-state database."],"a":[0,4],"m":true,"src":"Questions 1-50","si":30},{"s":31,"q":"In an OSPF network which OSPF structure is used to create the neighbor table on a router?","o":["adjacency database","link-state database","routing table","forwarding database"],"a":[0],"src":"Questions 1-50","si":31},{"s":32,"q":"What protocol is used in a system that consists of three elements--a manager, agents, and an information database?","o":["MPLS","SYSLOG","SNMP","TFTP"],"a":[2],"src":"Questions 1-50","si":32},{"s":33,"q":"What type of traffic is described as not resilient to loss?","o":["data","video","voice"],"a":[1],"src":"Questions 1-50","si":33},{"s":34,"q":"Refer to the exhibit. Router R1 is configured with static NAT. Addressing on the router and the web server are correctly configured, but there is no connectivity between the web server and users on the Internet. What is a possible reason for this lack of connectivity?","o":["Interface Fa0/0 should be configured with the command ip nat outside .","The inside global address is incorrect.","The router NAT configuration has an incorrect inside local address.","The NAT configuration on interface S0/0/1 is incorrect."],"a":[2],"src":"Questions 1-50","si":34,"e":1},{"s":35,"q":"Which type of API would be used to allow authorized salespeople of an organization access to internal sales data from their mobile devices?","o":["open","partner","public","private"],"a":[3],"src":"Questions 1-50","si":35},{"s":36,"q":"Refer to the exhibit. Which data format is used to represent the data for network automation applications?","o":["XML","HTML","YAML","JSON"],"a":[0],"src":"Questions 1-50","si":36,"e":1},{"s":37,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 101 permit udp 192.168.100.32 0.0.0.7 host 198.133.219.76 eq telnet\n\nIf a packet with a source address of 198.133.219.100, a destination address of 198.133.219.170, and a protocol of 23 is received on the interface, is the packet permitted or denied?","o":["denied","permitted"],"a":[0],"src":"Questions 1-50","si":37},{"s":38,"q":"Refer to the exhibit. If no router ID was manually configured, what would router R1 use as its OSPF router ID?","o":["10.0.0.1","10.1.0.1","192.168.1.100","209.165.201.1"],"a":[2],"src":"Questions 1-50","si":38,"e":1},{"s":39,"q":"What protocol is a vendor-neutral Layer 2 protocol that advertises the identity and capabilities of the host device to other connected network devices?","o":["LLDP","NTP","TFTP","SNMP"],"a":[0],"src":"Questions 1-50","si":39},{"s":40,"q":"Which type of VPN uses a hub-and-spoke configuration to establish a full mesh topology?","o":["MPLS VPN","GRE over IPsec","IPsec virtual tunnel interface","dynamic multipoint VPN"],"a":[3],"src":"Questions 1-50","si":40},{"s":41,"q":"What is a characteristic of the REST API?","o":["evolved into what became SOAP","used for exchanging XML structured information over HTTP or SMTP","considered slow, complex, and rigid","most widely used API for web services"],"a":[3],"src":"Questions 1-50","si":41},{"s":42,"q":"A student, doing a summer semester of study overseas, has taken hundreds of pictures on a smartphone and wants to back them up in case of loss. What service or technology would support this requirement?","o":["Cisco ACI","cloud services","software defined networking","dedicated servers"],"a":[1],"src":"Questions 1-50","si":42},{"s":43,"q":"Consider the following access list that allows IP phone configuration file transfers from a particular host to a TFTP server:\n\nR1(config)# access-list 105 permit udp host 10.0.70.23 host 10.0.54.5 range 1024 5000\nR1(config)# access-list 105 deny ip any any\nR1(config)# interface gi0/0\nR1(config-if)# ip access-group 105 out\n\nWhich method would allow the network administrator to modify the ACL and include FTP transfers from any source IP address?","o":["R1(config)# interface gi0/0\nR1(config-if)# no ip access-group 105 out\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 20\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 21\nR1(config)# interface gi0/0\nR1(config-if)# ip access-group 105 out","R1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 20\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 21","R1(config)# interface gi0/0\nR1(config-if)# no ip access-group 105 out\nR1(config)# no access-list 105\nR1(config)# access-list 105 permit udp host 10.0.70.23 host 10.0.54.5 range 1024 5000\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 20\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 21\nR1(config)# access-list 105 deny ip any any\nR1(config)# interface gi0/0\nR1(config-if)# ip access-group 105 out","R1(config)# access-list 105 permit udp host 10.0.70.23 host 10.0.54.5 range 1024 5000\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 20\nR1(config)# access-list 105 permit tcp any host 10.0.54.5 eq 21\nR1(config)# access-list 105 deny ip any any"],"a":[2],"src":"Questions 1-50","si":43},{"s":44,"q":"Which three statements are generally considered to be best practices in the placement of ACLs? (Choose three.)","o":["Filter unwanted traffic before it travels onto a low-bandwidth link.","Place standard ACLs close to the destination IP address of the traffic.","Place standard ACLs close to the source IP address of the traffic.","Place extended ACLs close to the destination IP address of the traffic.","Place extended ACLs close to the source IP address of the traffic.","For every inbound ACL placed on an interface, there should be a matching outbound ACL."],"a":[0,1,4],"m":true,"src":"Questions 1-50","si":44},{"s":46,"q":"What command would be used as part of configuring NAT or PAT to display all static translations that have been configured?","o":["show ip nat translations","show ip pat translations","show ip cache","show running-config"],"a":[0],"src":"Questions 1-50","si":45},{"s":47,"q":"A network administrator modified an OSPF-enabled router to have a hello timer setting of 20 seconds. What is the new dead interval time setting by default?","o":["40 seconds","60 seconds","80 seconds","100 seconds"],"a":[2],"src":"Questions 1-50","si":46},{"s":48,"q":"Which type of VPN is the preferred choice for support and ease of deployment for remote access?","o":["SSL VPN","GRE over IPsec","dynamic multipoint VPN","IPsec virtual tunnel interface"],"a":[0],"src":"Questions 1-50","si":47},{"s":49,"q":"What type of traffic is described as predictable and smooth?","o":["video","data","voice"],"a":[2],"src":"Questions 1-50","si":48},{"s":1,"q":"Which queuing mechanism has no provision for prioritizing or buffering but simply forwards packets in the order they arrive?","o":["FIFO","LLQ","CBWFQ","WFQ"],"a":[0],"src":"Questions 51-100","si":1},{"s":2,"q":"Refer to the exhibit. A network administrator has configured OSPFv2 on the two Cisco routers. The routers are unable to form a neighbor adjacency. What should be done to fix the problem on router R2?","o":["Implement the command no passive-interface Serial0/1.","Implement the command network 192.168.2.6 0.0.0.0 area 0 on router R2.","Change the router-id of router R2 to 2.2.2.2.","Implement the command network 192.168.3.1 0.0.0.0 area 0 on router R2."],"a":[0],"src":"Questions 51-100","si":2,"e":1},{"s":3,"q":"A network administrator is troubleshooting an OSPF problem that involves neighbor adjacency. What should the administrator do?","o":["Make sure that the router priority is unique on each router.","Make sure that the DR/BDR election is complete.","Make sure that the router ID is included in the hello packet.","Make sure that the hello and dead interval timers are the same on all routers."],"a":[3],"src":"Questions 51-100","si":3},{"s":4,"q":"Refer to the exhibit. Internet privileges for an employee have been revoked because of abuse but the employee still needs access to company resources. What is the best ACL type and placement to use in this situation?","o":["standard ACL inbound on R2 WAN interface connecting to the internet","standard ACL outbound on R2 WAN interface towards the internet","standard ACL inbound on R1 G0/0","standard ACL outbound on R1 G0/0"],"a":[1],"src":"Questions 51-100","si":4,"e":1},{"s":5,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 100 permit tcp 192.168.10.0 0.0.0.255 172.17.200.0 0.0.0.255 eq www\nIf a packet with a source address of 192.168.10.244, a destination address of 172.17.200.56, and a protocol of 80 is received on the interface, is the packet permitted or denied?","o":["denied","permitted"],"a":[1],"src":"Questions 51-100","si":5},{"s":6,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use applications such as Nmap, SuperScan, and Angry IP Scanner?","o":["to detect installed tools within files and directories that provide threat actors remote access and control over a computer or network","to detect any evidence of a hack or malware in a computer or network","to reverse engineer binary files when writing exploits and when analyzing malware","to probe network devices, servers, and hosts for open TCP or UDP ports"],"a":[3],"src":"Questions 51-100","si":6},{"s":7,"q":"What command would be used as part of configuring NAT or PAT to display any dynamic PAT translations that have been created by traffic?","o":["show ip pat translations","show ip cache","show running-config","show ip nat translations"],"a":[3],"src":"Questions 51-100","si":7},{"s":8,"q":"An administrator is configuring single-area OSPF on a router. One of the networks that must be advertised is 172.16.91.0 255.255.255.192. What wildcard mask would the administrator use in the OSPF network statement?","o":["0.0.31.255","0.0.0.63","0.0.15.255","0.0.7.255"],"a":[1],"src":"Questions 51-100","si":8},{"s":9,"q":"What type of traffic is described as requiring latency to be no more than 400 milliseconds (ms)?","o":["video","data","voice"],"a":[0],"src":"Questions 51-100","si":9},{"s":11,"q":"A network administrator is writing a standard ACL that will deny any traffic from the 172.16.0.0/16 network, but permit all other traffic. Which two commands should be used? (Choose two.)","o":["Router(config)# access-list 95 deny 172.16.0.0 255.255.0.0","Router(config)# access-list 95 permit any","Router(config)# access-list 95 host 172.16.0.0","Router(config)# access-list 95 deny 172.16.0.0 0.0.255.255","Router(config)# access-list 95 172.16.0.0 255.255.255.255","Router(config)# access-list 95 deny any"],"a":[1,3],"m":true,"src":"Questions 51-100","si":10},{"s":12,"q":"Refer to the exhibit. The company has decided that no traffic initiating from any other existing or future network can be transmitted to the Research and Development network. Furthermore, no traffic that originates from the Research and Development network can be transmitted to any other existing or future networks in the company. The network administrator has decided that extended ACLs are better suited for these requirements. Based on the information given, what will the network administrator do?","o":["One ACL will be placed on the R1 Gi0/0 interface and one ACL will be placed on the R2 Gi0/0 interface.","Only a numbered ACL will work for this situation.","One ACL will be placed on the R2 Gi0/0 interface and one ACL will be placed on the R2 S0/0/0 interface.","Two ACLs (one in each direction) will be placed on the R2 Gi0/0 interface."],"a":[3],"src":"Questions 51-100","si":11,"e":1},{"s":13,"q":"What protocol uses smaller stratum numbers to indicate that the server is closer to the authorized time source than larger stratum numbers?","o":["TFTP","SYSLOG","NTP","MPLS"],"a":[2],"src":"Questions 51-100","si":12},{"s":15,"q":"Refer to the exhibit. A web designer calls to report that the web server web-s1.cisco.com is not reachable through a web browser. The technician uses command line utilities to verify the problem and to begin the troubleshooting process. Which two things can be determined about the problem? (Choose two.)","o":["The web server at 192.168.0.10 is reachable from the source host.","DNS cannot resolve the IP address for the server web-s1.cisco.com.","A router is down between the source host and the server web-s1.cisco.com.","There is a problem with the web server software on web-s1.cisco.com.","The default gateway between the source host and the server at 192.168.0.10 is down."],"a":[0,1],"m":true,"src":"Questions 51-100","si":13,"e":1},{"s":16,"q":"What type of traffic is described as tending to be unpredictable, inconsistent, and bursty?","o":["video","voice","data"],"a":[0],"src":"Questions 51-100","si":14},{"s":18,"q":"What type of traffic is described as consisting of traffic that requires a higher priority if interactive?","o":["voice","data","video"],"a":[1],"src":"Questions 51-100","si":15},{"s":19,"q":"Which type of VPN provides a flexible option to connect a central site with branch sites?","o":["IPsec virtual tunnel interface","MPLS VPN","dynamic multipoint VPN","GRE over IPsec"],"a":[2],"src":"Questions 51-100","si":16},{"s":20,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use fuzzers?","o":["to discover security vulnerabilities of a computer","to detect any evidence of a hack or malware in a computer or network","to reverse engineer binary files when writing exploits and when analyzing malware","to detect installed tools within files and directories that provide threat actors remote access and control over a computer or network"],"a":[0],"src":"Questions 51-100","si":17},{"s":21,"q":"Refer to the exhibit. A network administrator has configured a standard ACL to permit only the two LAN networks attached to R1 to access the network that connects to R2 G0/1 interface, but not the G0/0 interface. When following the best practices, in what location should the standard ACL be applied?","o":["R1 S0/0/0 outbound","R2 G0/0 outbound","R2 S0/0/1 outbound","R1 S0/0/0 inbound","R2 G0/1 inbound"],"a":[1],"src":"Questions 51-100","si":18,"e":1},{"s":22,"q":"Two OSPF-enabled routers are connected over a point-to-point link. During the ExStart state, which router will be chosen as the first one to send DBD packets?","o":["the router with the highest router ID","the router with the lowest IP address on the connecting interface","the router with the highest IP address on the connecting interface","the router with the lowest router ID"],"a":[0],"src":"Questions 51-100","si":19},{"s":23,"q":"Which step in the link-state routing process is described by a router sending Hello packets out all of the OSPF-enabled interfaces?","o":["exchanging link-state advertisements","electing the designated router","injecting the default route","establishing neighbor adjacencies"],"a":[3],"src":"Questions 51-100","si":20},{"s":24,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use forensic tools?","o":["to obtain specially designed operating systems preloaded with tools optimized for hacking","to detect any evidence of a hack or malware in a computer or network","to detect installed tools within files and directories that provide threat actors remote access and control over a computer or network","to reverse engineer binary files when writing exploits and when analyzing malware"],"a":[1],"src":"Questions 51-100","si":21},{"s":25,"q":"Refer to the exhibit. A network administrator has configured OSPFv2 on the two Cisco routers but PC1 is unable to connect to PC2. What is the most likely problem?","o":["Interface Fa0/0 has not been activated for OSPFv2 on router R2.","Interface Fa0/0 is configured as a passive-interface on router R2.","Interface S0/0 is configured as a passive-interface on router R2.","Interface s0/0 has not been activated for OSPFv2 on router R2."],"a":[0],"src":"Questions 51-100","si":22,"e":1},{"s":26,"q":"ABCTech is investigating the use of automation for some of its products. In order to control and test these products, the programmers require Windows, Linux, and MAC OS on their computers. What service or technology would support this requirement?","o":["dedicated servers","software defined networking","virtualization","Cisco ACI"],"a":[2],"src":"Questions 51-100","si":23},{"s":27,"q":"A network engineer has noted that some expected network route entries are not displayed in the routing table. Which two commands will provide additional information about the state of router adjacencies, timer intervals, and the area ID? (Choose two.)","o":["show ip protocols","show ip ospf neighbor","show running-configuration","show ip ospf interface","show ip route ospf"],"a":[1,3],"m":true,"src":"Questions 51-100","si":24},{"s":28,"q":"Which type of VPN involves the forwarding of traffic over the backbone through the use of labels distributed among core routers?","o":["MPLS VPN","GRE over IPsec","IPsec virtual tunnel interface","dynamic multipoint VPN"],"a":[0],"src":"Questions 51-100","si":25},{"s":29,"q":"Which type of VPN involves a nonsecure tunneling protocol being encapsulated by IPsec?","o":["SSL VPN","dynamic multipoint VPN","GRE over IPsec","IPsec virtual tunnel interface"],"a":[2],"src":"Questions 51-100","si":26},{"s":30,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use hacking operation systems?","o":["to detect any evidence of a hack or malware in a computer or network","to obtain specially designed operating systems preloaded with tools optimized for hacking","to encode data, using algorithm schemes, to prevent unauthorized access to the encrypted data","to reverse engineer binary files when writing exploits and when analyzing malware"],"a":[1],"src":"Questions 51-100","si":27},{"s":31,"q":"What command would be used as part of configuring NAT or PAT to identify an interface as part of the external global network?","o":["ip pat inside","access-list 10 permit 172.19.89.0 0.0.0.255","ip nat inside","ip nat outside"],"a":[3],"src":"Questions 51-100","si":28},{"s":32,"q":"To avoid purchasing new hardware, a company wants to take advantage of idle system resources and consolidate the number of servers while allowing for multiple operating systems on a single hardware platform. What service or technology would support this requirement?","o":["dedicated servers","cloud services","virtualization","data center"],"a":[2],"src":"Questions 51-100","si":29},{"s":33,"q":"Which type of VPN routes packets through virtual tunnel interfaces for encryption and forwarding?","o":["MPLS VPN","IPsec virtual tunnel interface","dynamic multipoint VPN","GRE over IPsec"],"a":[1],"src":"Questions 51-100","si":30},{"s":34,"q":"Which step in the link-state routing process is described by a router flooding link-state and cost information about each directly connected link?","o":["building the topology table","selecting the router ID","exchanging link-state advertisements","injecting the default route"],"a":[2],"src":"Questions 51-100","si":31},{"s":35,"q":"What type of traffic is described as using either TCP or UDP depending on the need for error recovery?","o":["video","voice","data"],"a":[2],"src":"Questions 51-100","si":32},{"s":36,"q":"Refer to the exhibit. The company CEO demands that one ACL be created to permit email traffic to the internet and deny FTP access. What is the best ACL type and placement to use in this situation?","o":["extended ACL outbound on R2 WAN interface towards the internet","standard ACL outbound on R2 S0/0/0","extended ACL inbound on R2 S0/0/0","standard ACL inbound on R2 WAN interface connecting to the internet"],"a":[0],"src":"Questions 51-100","si":33,"e":1},{"s":37,"q":"What command would be used as part of configuring NAT or PAT to define a pool of addresses for translation?","o":["ip nat inside source static 172.19.89.13 198.133.219.65","ip nat inside source list 24 interface serial 0/1/0 overload","ip nat pool POOL-STAT 64.100.14.17 64.100.14.30 netmask 255.255.255.240","ip nat outside"],"a":[2],"src":"Questions 51-100","si":34},{"s":38,"q":"What is the name of the layer in the Cisco borderless switched network design that is considered to be the backbone used for high-speed connectivity and fault isolation?","o":["data link","access","core","network","network access"],"a":[2],"src":"Questions 51-100","si":35},{"s":39,"q":"An ACL is applied inbound on router interface. The ACL consists of a single entry:\n\naccess-list 210 permit tcp 172.18.20.0 0.0.0.47 any eq ftp\n\nIf a packet with a source address of 172.18.20.40, a destination address of 10.33.19.2, and a protocol of 21 is received on the interface, is the packet permitted or denied?","o":["permitted","denied"],"a":[0],"src":"Questions 51-100","si":36},{"s":40,"q":"What type of traffic is described as consisting of traffic that gets a lower priority if it is not mission-critical?","o":["video","data","voice"],"a":[1],"src":"Questions 51-100","si":37},{"s":41,"q":"Which OSPF table is identical on all converged routers within the same OSPF area?","o":["routing","neighbor","adjacency","topology"],"a":[3],"src":"Questions 51-100","si":38},{"s":42,"q":"An ACL is applied inbound on router interface. The ACL consists of a single entry:\n\naccess-list 100 permit tcp 192.168.10.0 0.0.0.255 any eq www\n\nIf a packet with a source address of 192.168.10.45, a destination address of 10.10.3.27, and a protocol of 80 is received on the interface, is the packet permitted or denied?","o":["permitted","denied"],"a":[0],"src":"Questions 51-100","si":39},{"s":43,"q":"What protocol allows the manager to poll agents to access information from the agent MIB?","o":["CBWFQ","SYSLOG","TFTP","SNMP"],"a":[3],"src":"Questions 51-100","si":40},{"s":46,"q":"What type of traffic is described as being able to tolerate a certain amount of latency, jitter, and loss without any noticeable effects?","o":["voice","video","data"],"a":[0],"src":"Questions 51-100","si":41},{"s":47,"q":"Which design feature will limit the size of a failure domain in an enterprise network?","o":["the purchase of enterprise equipment that is designed for large traffic volume","the installation of redundant power supplies","the use of a collapsed core design","the use of the building switch block approach"],"a":[3],"src":"Questions 51-100","si":42},{"s":48,"q":"Which two things should a network administrator modify on a router to perform password recovery? (Choose two.)","o":["the system image file","the NVRAM file system","the configuration register value","the startup configuration file","system ROM"],"a":[2,3],"m":true,"src":"Questions 51-100","si":43},{"s":49,"q":"What type of network uses one common infrastructure to carry voice, data, and video signals?","o":["borderless","converged","managed","switched"],"a":[1],"src":"Questions 51-100","si":44},{"s":50,"q":"What are three advantages of using private IP addresses and NAT? (Choose three.)","o":["hides private LAN addressing from outside devices that are connected to the Internet","permits LAN expansion without additional public IP addresses","reduces CPU usage on customer routers","creates multiple public IP addresses","improves the performance of the router that is connected to the Internet","conserves registered public IP addresses"],"a":[0,1,5],"m":true,"src":"Questions 51-100","si":45},{"s":1,"q":"Which two scenarios are examples of remote access VPNs? (Choose two.)","o":["All users at a large branch office can access company resources through a single VPN connection.","A small branch office with three employees has a Cisco ASA that is used to create a VPN connection to the HQ.","A toy manufacturer has a permanent VPN connection to one of its parts suppliers.","A mobile sales agent is connecting to the company network via the Internet connection at a hotel.","An employee who is working from home uses VPN client software on a laptop in order to connect to the company network."],"a":[3,4],"m":true,"src":"Questions 101-150","si":1},{"s":2,"q":"What are three benefits of cloud computing? (Choose three.)","o":["It utilizes end-user clients to do a substantial amount of data preprocessing and storage.","It uses open-source software for distributed processing of large datasets.","It streamlines the IT operations of an organization by subscribing only to needed services.","It enables access to organizational data anywhere and at any time.","It turns raw data into meaningful information by discovering patterns and relationships.","It eliminates or reduces the need for onsite IT equipment, maintenance, and management."],"a":[2,3,5],"m":true,"src":"Questions 101-150","si":2},{"s":3,"q":"What is a characteristic of a single-area OSPF network?","o":["All routers share a common forwarding database.","All routers have the same neighbor table.","All routers are in the backbone area.","All routers have the same routing table."],"a":[2],"src":"Questions 101-150","si":3},{"s":4,"q":"What is a WAN?","o":["a network infrastructure that spans a limited physical area such as a city","a network infrastructure that provides access to other networks over a large geographic area","a network infrastructure that provides access in a small geographic area","a network infrastructure designed to provide data storage, retrieval, and replication"],"a":[1],"src":"Questions 101-150","si":4},{"s":5,"q":"A network administrator has been tasked with creating a disaster recovery plan. As part of this plan, the administrator is looking for a backup site for all of the data on the company servers. What service or technology would support this requirement?","o":["data center","virtualization","dedicated servers","software defined networking"],"a":[0],"src":"Questions 101-150","si":5},{"s":6,"q":"Which type of OSPF packet is used by a router to discover neighbor routers and establish neighbor adjacency?","o":["link-state update","hello","database description","link-state request"],"a":[1],"src":"Questions 101-150","si":6},{"s":7,"q":"Which two statements are characteristics of a virus? (Choose two.)","o":["A virus has an enabling vulnerability, a propagation mechanism, and a payload.","A virus can be dormant and then activate at a specific time or date.","A virus provides the attacker with sensitive data, such as passwords.","A virus replicates itself by independently exploiting vulnerabilities in networks.","A virus typically requires end-user activation."],"a":[1,4],"m":true,"src":"Questions 101-150","si":7},{"s":8,"q":"Which public WAN access technology utilizes copper telephone lines to provide access to subscribers that are multiplexed into a single T3 link connection?","o":["ISDN","DSL","cable","dialup"],"a":[1],"src":"Questions 101-150","si":8},{"s":9,"q":"A customer needs a metropolitan area WAN connection that provides high-speed, dedicated bandwidth between two sites. Which type of WAN connection would best fulfill this need?","o":["packet-switched network","Ethernet WAN","circuit-switched network","MPLS"],"a":[1],"src":"Questions 101-150","si":9},{"s":10,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use debuggers?","o":["to detect installed tools within files and directories that provide threat actors remote access and control over a computer or network","to reverse engineer binary files when writing exploits and when analyzing malware","to obtain specially designed operating systems preloaded with tools optimized for hacking","to detect any evidence of a hack or malware in a computer or network"],"a":[1],"src":"Questions 101-150","si":10},{"s":11,"q":"Consider the following output for an ACL that has been applied to a router via the access-class in command. What can a network administrator determine from the output that is shown?\n\nR1#\nStandard IP access list 2\n10 permit 192.168.10.0, wildcard bits 0.0.0.255 (2 matches)\n20 deny any (1 match)","o":["Two devices connected to the router have IP addresses of 192.168.10. x .","Two devices were able to use SSH or Telnet to gain access to the router.","Traffic from one device was not allowed to come into one router port and be routed outbound a different router port.","Traffic from two devices was allowed to enter one router port and be routed outbound to a different router port."],"a":[1],"src":"Questions 101-150","si":11},{"s":12,"q":"What command would be used as part of configuring NAT or PAT to clear dynamic entries before the timeout has expired?","o":["clear ip dhcp","clear ip nat translation","clear access-list counters","clear ip pat statistics"],"a":[1],"src":"Questions 101-150","si":12},{"s":13,"q":"What are two characteristics of video traffic? (Choose two.)","o":["Video traffic consumes less network resources than voice traffic consumes.","Video traffic latency should not exceed 400 ms.","Video traffic is more resilient to loss than voice traffic is.","Video traffic requires a minimum of 30 kbs of bandwidth.","Video traffic is unpredictable and inconsistent."],"a":[1,4],"m":true,"src":"Questions 101-150","si":13},{"s":14,"q":"Refer to the exhibit. A technician is configuring R2 for static NAT to allow the client to access the web server. What is a possible reason that the client PC cannot access the web server?","o":["The IP NAT statement is incorrect.","Interface Fa0/1 should be identified as the outside NAT interface.","Interface S0/0/0 should be identified as the outside NAT interface.","The configuration is missing a valid access control list."],"a":[2],"src":"Questions 101-150","si":14,"e":1},{"s":16,"q":"A data center has recently updated a physical server to host multiple operating systems on a single CPU. The data center can now provide each customer with a separate web server without having to allocate an actual discrete server for each customer. What is the networking trend that is being implemented by the data center in this situation?","o":["online collaboration","BYOD","virtualization","maintaining communication integrity"],"a":[2],"src":"Questions 101-150","si":15},{"s":17,"q":"Refer to the exhibit. Which address or addresses represent the inside global address?","o":["192.168.0.100","10.1.1.2","any address in the 10.1.1.0 network","209.165.20.25"],"a":[3],"src":"Questions 101-150","si":16,"e":1},{"s":18,"q":"Which two IPsec protocols are used to provide data integrity?","o":["MD5","DH","AES","SHA","RSA"],"a":[0,3],"m":true,"src":"Questions 101-150","si":17},{"s":19,"q":"If an outside host does not have the Cisco AnyConnect client preinstalled, how would the host gain access to the client image?","o":["The Cisco AnyConnect client is installed by default on most major operating systems.","The host initiates a clientless VPN connection using a compliant web browser to download the client.","The host initiates a clientless connection to a TFTP server to download the client.","The host initiates a clientless connection to an FTP server to download the client."],"a":[1],"src":"Questions 101-150","si":18},{"s":20,"q":"A company is considering updating the campus WAN connection. Which two WAN options are examples of the private WAN architecture? (Choose two.)","o":["leased line","cable","digital subscriber line","Ethernet WAN","municipal Wi-Fi"],"a":[0,3],"m":true,"src":"Questions 101-150","si":19},{"s":21,"q":"Which type of QoS marking is applied to Ethernet frames?","o":["IP precedence","DSCP","ToS","CoS"],"a":[3],"src":"Questions 101-150","si":20},{"s":22,"q":"Refer to the exhibit. Routers R1 and R2 are connected via a serial link. One router is configured as the NTP master, and the other is an NTP client. Which two pieces of information can be obtained from the partial output of the show ntp associations detail command on R2? (Choose two.)","o":["Both routers are configured to use NTPv2.","Router R1 is the master, and R2 is the client","The IP address of R2 is 192 168.1.2.","Router R2 is the master, and R1 is the client","The IP address of R1 is 192.168.1.2"],"a":[1,4],"m":true,"src":"Questions 101-150","si":21,"e":1},{"s":25,"q":"Which is a characteristic of a Type 2 hypervisor?","o":["does not require management console software","has direct access to server hardware resources","best suited for enterprise environments","installs directly on hardware"],"a":[0],"src":"Questions 101-150","si":22},{"s":26,"q":"What are the two types of VPN connections? (Choose two.)","o":["PPPoE","Frame Relay","site-to-site","remote access","leased line"],"a":[2,3],"m":true,"src":"Questions 101-150","si":23},{"s":27,"q":"Refer to the exhibit. What three conclusions can be drawn from the displayed output? (Choose three.)","o":["The DR can be reached through the GigabitEthernet 0/0 interface.","There have been 9 seconds since the last hello packet sent.","This interface is using the default priority.","The router ID values were not the criteria used to select the DR and the BDR.","The router ID on the DR router is 3.3.3.3","The BDR has three neighbors."],"a":[0,1,3],"m":true,"src":"Questions 101-150","si":24,"e":1},{"s":28,"q":"Refer to the exhibit. A network administrator is configuring an ACL to limit the connection to R1 vty lines to only the IT group workstations in the network 192.168.22.0/28. The administrator verifies the successful Telnet connections from a workstation with IP 192.168.22.5 to R1 before the ACL is applied. However, after the ACL is applied to the interface Fa0/0, Telnet connections are denied. What is the cause of the connection failure?","o":["The enable secret password is not configured on R1.","The IT group network is included in the deny statement.","The permit ACE specifies a wrong port number.","The permit ACE should specify protocol ip instead of tcp.","The login command has not been entered for vty lines."],"a":[1],"src":"Questions 101-150","si":25,"e":1},{"s":29,"q":"What functionality does mGRE provide to the DMVPN technology?","o":["It allows the creation of dynamically allocated tunnels through a permanent tunnel source at the hub and dynamically allocated tunnel destinations at the spokes.","It provides secure transport of private information over public networks, such as the Internet.","It is a Cisco software solution for building multiple VPNs in an easy, dynamic, and scalable manner.","It creates a distributed mapping database of public IP addresses for all VPN tunnel spokes."],"a":[0],"src":"Questions 101-150","si":26},{"s":30,"q":"What is used to pre-populate the adjacency table on Cisco devices that use CEF to process packets?","o":["the FIB","the routing table","the ARP table","the DSP"],"a":[2],"src":"Questions 101-150","si":27,"e":1},{"s":31,"q":"What command would be used as part of configuring NAT or PAT to display information about NAT configuration parameters and the number of addresses in the pool?","o":["show running-config","show ip nat statistics","show ip cache","show version"],"a":[1],"src":"Questions 101-150","si":28},{"s":32,"q":"What is a purpose of establishing a network baseline?","o":["It provides a statistical average for network performance.","It creates a point of reference for future network evaluations.","It manages the performance of network devices.","It checks the security configuration of network devices."],"a":[1],"src":"Questions 101-150","si":29},{"s":34,"q":"Which statement describes a characteristic of standard IPv4 ACLs?","o":["They filter traffic based on source IP addresses only.","They can be created with a number but not with a name.","They are configured in the interface configuration mode.","They can be configured to filter traffic based on both source IP addresses and source ports."],"a":[0],"src":"Questions 101-150","si":30},{"s":35,"q":"Refer to the exhibit. R1 is configured for NAT as displayed. What is wrong with the configuration?","o":["NAT-POOL2 is not bound to ACL 1.","Interface Fa0/0 should be identified as an outside NAT interface.","The NAT pool is incorrect.","Access-list 1 is misconfigured."],"a":[0],"src":"Questions 101-150","si":31,"e":1},{"s":36,"q":"Refer to the exhibit. What method can be used to enable an OSPF router to advertise a default route to neighboring OSPF routers?","o":["Use a static route pointing to the ISP and redistribute it.","Use the redistribute static command on R0-A.","Use the default-information originate command on ISP.","Use the default-information originate command on R0-A."],"a":[3],"src":"Questions 101-150","si":32,"e":1},{"s":37,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use applications such as John the Ripper,THC Hydra, RainbowCrack, and Medusa?","o":["to capture and analyze packets within traditional Ethernet LANs or WLANs","to probe and test the robustness of a firewall by using specially created forged packets","to make repeated guesses in order to crack a password"],"a":[2],"src":"Questions 101-150","si":33},{"s":38,"q":"What are two syntax rules for writing a JSON array? (Choose two.)","o":["Each value in the array is separated by a comma.","The array can include only one value type.","A space must separate each value in the array.","A semicolon separates the key and list of values.","Values are enclosed in square brackets."],"a":[0,4],"m":true,"src":"Questions 101-150","si":34},{"s":39,"q":"What is a characteristic of a Trojan horse as it relates to network security?","o":["An electronic dictionary is used to obtain a password to be used to infiltrate a key network device.","Malware is contained in a seemingly legitimate executable program.","Extreme quantities of data are sent to a particular network device interface.","Too much information is destined for a particular memory block, causing additional memory areas to be affected"],"a":[1],"src":"Questions 101-150","si":35},{"s":40,"q":"An attacker is redirecting traffic to a false default gateway in an attempt to intercept the data traffic of a switched network. What type of attack could achieve this?","o":["TCP SYN flood","DNS tunneling","DHCP spoofing","ARP cache poisoning"],"a":[2],"src":"Questions 101-150","si":36},{"s":41,"q":"A company is developing a security policy for secure communication. In the exchange of critical messages between a headquarters office and a branch office, a hash value should only be recalculated with a predetermined code, thus ensuring the validity of data source. Which aspect of secure communications is addressed?","o":["data integrity","non-repudiation","origin authentication","data confidentiality"],"a":[2],"src":"Questions 101-150","si":37},{"s":42,"q":"A company has contracted with a network security firm to help identify the vulnerabilities of the corporate network. The firm sends a team to perform penetration tests to the company network. Why would the team use packet sniffers?","o":["to detect installed tools within files and directories that provide threat actors remote access and control over a computer or network","to detect any evidence of a hack or malware in a computer or network","to probe and test the robustness of a firewall by using specially created forged packets","to capture and analyze packets within traditional Ethernet LANs or WLANs"],"a":[3],"src":"Questions 101-150","si":38},{"s":43,"q":"An administrator is configuring single-area OSPF on a router. One of the networks that must be advertised is 192.168.0.0 255.255.252.0. What wildcard mask would the administrator use in the OSPF network statement?","o":["0.0.15.255","0.0.3.255","0.0.7.255","0.0.1.255"],"a":[1],"src":"Questions 101-150","si":39},{"s":46,"q":"What is one reason to use the ip ospf priority command when the OSPF routing protocol is in use?","o":["to activate the OSPF neighboring process","to influence the DR/BDR election process","to provide a backdoor for connectivity during the convergence process","to streamline and speed up the convergence process"],"a":[1],"src":"Questions 101-150","si":40},{"s":47,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 210 permit tcp 172.18.20.0 0.0.0.31 172.18.20.32 0.0.0.31 eq ftp\n\nIf a packet with a source address of 172.18.20.14, a destination address of 172.18.20.40, and a protocol of 21 is received on the interface, is the packet permitted or denied?","o":["permitted","denied"],"a":[0],"src":"Questions 101-150","si":41},{"s":48,"q":"What is a characteristic of the two-tier spine-leaf topology of the Cisco ACI fabric architecture?","o":["The spine and leaf switches are always linked through core switches.","The spine switches attach to the leaf switches and attach to each other for redundancy.","The leaf switches always attach to the spines and they are interlinked through a trunk line.","The leaf switches always attach to the spines, but they never attach to each other."],"a":[3],"src":"Questions 101-150","si":42},{"s":49,"q":"Which two scenarios would result in a duplex mismatch? (Choose two.)","o":["connecting a device with autonegotiation to another that is manually set to full-duplex","starting and stopping a router interface during a normal operation","connecting a device with an interface running at 100 Mbps to another with an interface running at 1000 Mbps","configuring dynamic routing incorrectly","manually setting the two connected devices to different duplex modes"],"a":[0,4],"m":true,"src":"Questions 101-150","si":43},{"s":50,"q":"A network technician is configuring SNMPv3 and has set a security level of auth . What is the effect of this setting?","o":["authenticates a packet by a string match of the username or community string","authenticates a packet by using either the HMAC with MD5 method or the SHA method","authenticates a packet by using either the HMAC MD5 or 3.HMAC SHA algorithms and encrypts the packet with either the DES, 3DES or AES algorithms","authenticates a packet by using the SHA algorithm only"],"a":[1],"src":"Questions 101-150","si":44},{"s":2,"q":"What are two types of attacks used on DNS open resolvers? (Choose two.)","o":["amplification and reflection","resource utilization","fast flux","ARP poisoning","cushioning"],"a":[0,1],"m":true,"src":"Questions 150-216","si":1},{"s":3,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 101 permit udp 192.168.100.0 0.0.2.255 64.100.40.0 0.0.0.15 eq telnet\n\nIf a packet with a source address of 192.168.101.45, a destination address of 64.100.40.4, and a protocol of 23 is received on the interface, is the packet permitted or denied?","o":["denied","permitted"],"a":[0],"src":"Questions 150-216","si":2},{"s":5,"q":"Which type of resources are required for a Type 1 hypervisor?","o":["a dedicated VLAN","a management console","a host operating system"],"a":[1],"src":"Questions 150-216","si":3},{"s":6,"q":"In JSON, what is held within square brackets [ ]?","o":["nested values","key/value pairs","an object","an array"],"a":[3],"src":"Questions 150-216","si":4},{"s":7,"q":"What are three components used in the query portion of a typical RESTful API request? (Choose three.)","o":["resources","protocol","API server","format","key","parameters"],"a":[3,4,5],"m":true,"src":"Questions 150-216","si":5},{"s":8,"q":"A user reports that when the corporate web page URL is entered on a web browser, an error message indicates that the page cannot be displayed. The help-desk technician asks the user to enter the IP address of the web server to see if the page can be displayed. Which troubleshooting method is being used by the technician?","o":["top-down","bottom-up","divide-and-conquer","substitution"],"a":[2],"src":"Questions 150-216","si":6},{"s":9,"q":"Which protocol provides authentication, integrity, and confidentiality services and is a type of VPN?","o":["MD5","AES","IPsec","ESP"],"a":[2],"src":"Questions 150-216","si":7},{"s":10,"q":"Which statement describes a characteristic of Cisco Catalyst 2960 switches?","o":["They are best used as distribution layer switches.","New Cisco Catalyst 2960-C switches support PoE pass-through.","They are modular switches.","They do not support an active switched virtual interface (SVI) with IOS versions prior to 15.x."],"a":[1],"src":"Questions 150-216","si":8},{"s":11,"q":"Which component of the ACI architecture translates application policies into network programming?","o":["the hypervisor","the Application Policy Infrastructure Controller","the Nexus 9000 switch","the Application Network Profile endpoints"],"a":[1],"src":"Questions 150-216","si":9},{"s":12,"q":"Which two pieces of information should be included in a logical topology diagram of a network? (Choose two.)","o":["device type","cable specification","interface identifier","OS/IOS version","connection type","cable type and identifier"],"a":[2,4],"m":true,"src":"Questions 150-216","si":10},{"s":13,"q":"Refer to the exhibit. A PC at address 10.1.1.45 is unable to access the Internet. What is the most likely cause of the problem?","o":["The NAT pool has been exhausted.","The wrong netmask was used on the NAT pool.","Access-list 1 has not been configured properly.","The inside and outside interfaces have been configured backwards."],"a":[0],"src":"Questions 150-216","si":11,"e":1},{"s":14,"q":"What are two benefits of using SNMP traps? (Choose two.)","o":["They eliminate the need for some periodic polling requests.","They reduce the load on network and agent resources.","They limit access for management systems only.","They can provide statistics on TCP/IP packets that flow through Cisco devices.","They can passively listen for exported NetFlow datagrams."],"a":[0,1],"m":true,"src":"Questions 150-216","si":12},{"s":15,"q":"Which statement accurately describes a characteristic of IPsec?","o":["IPsec works at the application layer and protects all application data.","IPsec is a framework of standards developed by Cisco that relies on OSI algorithms.","IPsec is a framework of proprietary standards that depend on Cisco specific algorithms.","IPsec works at the transport layer and protects data at the network layer.","IPsec is a framework of open standards that relies on existing algorithms."],"a":[4],"src":"Questions 150-216","si":13},{"s":16,"q":"In a large enterprise network, which two functions are performed by routers at the distribution layer? (Choose two.)","o":["connect users to the network","provide a high-speed network backbone","connect remote networks","provide Power over Ethernet to devices","provide data traffic security"],"a":[2,4],"m":true,"src":"Questions 150-216","si":14},{"s":17,"q":"Which two statements describe the use of asymmetric algorithms?\n\n(Choose two.)","o":["Public and private keys may be used interchangeably.","If a public key is used to encrypt the data, a public key must be used to decrypt the data.","If a private key is used to encrypt the data, a public key must be used to decrypt the data.","If a public key is used to encrypt the data, a private key must be used to decrypt the data.","If a private key is used to encrypt the data, a private key must be used to decrypt the data."],"a":[2,3],"m":true,"src":"Questions 150-216","si":15},{"s":18,"q":"Refer to the exhibit. A network administrator has deployed QoS and has configured the network to mark traffic on the VoIP phones as well as the Layer 2 and Layer 3 switches. Where should initial marking occur to establish the trust boundary?","o":["Trust Boundary 4","Trust Boundary 3","Trust Boundary 1","Trust Boundary 2"],"a":[2],"src":"Questions 150-216","si":16,"e":1},{"s":19,"q":"What are two benefits of extending access layer connectivity to users through a wireless medium? (Choose two.)","o":["reduced costs","decreased number of critical points of failure","increased flexibility","increased bandwidth availability","increased network management options"],"a":[0,2],"m":true,"src":"Questions 150-216","si":17},{"s":20,"q":"What are two purposes of launching a reconnaissance attack on a network? (Choose two.)","o":["to scan for accessibility","to retrieve and modify data","to gather information about the network and devices","to prevent other users from accessing the system","to escalate access privileges"],"a":[0,2],"m":true,"src":"Questions 150-216","si":18},{"s":21,"q":"A group of users on the same network are all complaining about their computers running slowly. After investigating, the technician determines that these computers are part of a zombie network. Which type of malware is used to control these computers?","o":["botnet","spyware","virus","rootkit"],"a":[0],"src":"Questions 150-216","si":19},{"s":22,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 101 permit tcp 10.1.1.0 0.0.0.255 host 192.31.7.45 eq dns\n\nIf a packet with a source address of 10.1.1.201, a destination address of 192.31.7.45, and a protocol of 23 is received on the interface, is the packet permitted or denied?","o":["permitted","denied"],"a":[1],"src":"Questions 150-216","si":20},{"s":23,"q":"Refer to the exhibit. From which location did this router load the IOS?","o":["flash memory","NVRAM?","RAM","ROM","a TFTP server?"],"a":[0],"src":"Questions 150-216","si":21,"e":1},{"s":24,"q":"What QoS step must occur before packets can be marked?","o":["classifying","shaping","queuing","policing"],"a":[0],"src":"Questions 150-216","si":22},{"s":25,"q":"What is the main function of a hypervisor?","o":["It is used to create and manage multiple VM instances on a host machine.","It is a device that filters and checks security credentials.","It is a device that synchronizes a group of sensors.","It is software used to coordinate and prepare data for analysis.","It is used by ISPs to monitor cloud computing resources."],"a":[0],"src":"Questions 150-216","si":23},{"s":26,"q":"A company needs to interconnect several branch offices across a metropolitan area. The network engineer is seeking a solution that provides high-speed converged traffic, including voice, video, and data on the same network infrastructure. The company also wants easy integration to their existing LAN infrastructure in their office locations. Which technology should be recommended?","o":["Frame Relay","Ethernet WAN","VSAT","ISDN"],"a":[1],"src":"Questions 150-216","si":24},{"s":27,"q":"Refer to the exhibit. As traffic is forwarded out an egress interface with QoS treatment, which congestion avoidance technique is used?","o":["traffic shaping","weighted random early detection","classification and marking","traffic policing"],"a":[3],"src":"Questions 150-216","si":25,"e":1},{"s":28,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 101 permit tcp 10.1.1.0 0.0.0.255 host 10.1.3.8 eq dns\n\nIf a packet with a source address of 10.1.3.8, a destination address of 10.10.3.8, and a protocol of 53 is received on the interface, is the packet permitted or denied?","o":["denied","permitted"],"a":[0],"src":"Questions 150-216","si":26},{"s":29,"q":"Refer to the exhibit. What is the purpose of the command marked with an arrow shown in the partial configuration output of a Cisco broadband router?","o":["defines which addresses are allowed into the router","defines which addresses can be translated","defines which addresses are assigned to a NAT pool","defines which addresses are allowed out of the router"],"a":[1],"src":"Questions 150-216","si":27,"e":1},{"s":31,"q":"Refer to the exhibit. An administrator first configured an extended ACL as shown by the output of the show access-lists command. The administrator then edited this access-list by issuing the commands below.\n\nRouter(config)# ip access-list extended 101\nRouter(config-ext-nacl)# no 20\nRouter(config-ext-nacl)# 5 permit tcp any any eq 22\nRouter(config-ext-nacl)# 20 deny udp any any\n\nWhich two conclusions can be drawn from this new configuration? (Choose two.)","o":["TFTP packets will be permitted.","Ping packets will be permitted.","Telnet packets will be permitted.","SSH packets will be permitted.","All TCP and UDP packets will be denied."],"a":[1,3],"m":true,"src":"Questions 150-216","si":28,"e":1},{"s":32,"q":"Which troubleshooting approach is more appropriate for a seasoned network administrator rather than a less-experienced network administrator?","o":["a less-structured approach based on an educated guess","an approach comparing working and nonworking components to spot significant differences","a structured approach starting with the physical layer and moving up through the layers of the OSI model until the cause of the problem is identified","an approach that starts with the end-user applications and moves down through the layers of the OSI model until the cause of the problem has been identified"],"a":[0],"src":"Questions 150-216","si":29},{"s":33,"q":"Refer to the exhibit. Many employees are wasting company time accessing social media on their work computers. The company wants to stop this access. What is the best ACL type and placement to use in this situation?","o":["extended ACL outbound on R2 WAN interface towards the internet","standard ACL outbound on R2 WAN interface towards the internet","standard ACL outbound on R2 S0/0/0","extended ACLs inbound on R1 G0/0 and G0/1"],"a":[3],"src":"Questions 150-216","si":30,"e":1},{"s":34,"q":"Refer to the exhibit. An administrator is trying to configure PAT on R1, but PC-A is unable to access the Internet. The administrator tries to ping a server on the Internet from PC-A and collects the debugs that are shown in the exhibit. Based on this output, what is most likely the cause of the problem?","o":["The inside and outside NAT interlaces have been configured backwards","The inside global address is not on the same subnet as the ISP","The address on Fa0/0 should be 64.100.0.1.","The NAT source access list matches the wrong address range. b"],"a":[1],"src":"Questions 150-216","si":31,"e":1},{"s":35,"q":"Why is QoS an important issue in a converged network that combines voice, video, and data communications?","o":["Data communications must be given the first priority.","Voice and video communications are more sensitive to latency.","Legacy equipment is unable to transmit voice and video without QoS.","Data communications are sensitive to jitter."],"a":[1],"src":"Questions 150-216","si":32},{"s":36,"q":"Which statement describes a VPN?","o":["VPNs use logical connections to create public networks through the Internet.","VPNs use open source virtualization software to create the tunnel through the Internet.","VPNs use dedicated physical connections to transfer data between remote users.","VPNs use virtual connections to create a private network through a public network."],"a":[3],"src":"Questions 150-216","si":33},{"s":37,"q":"In which OSPF state is the DR/BDR election conducted?","o":["ExStart","Init","Two-Way","Exchange"],"a":[2],"src":"Questions 150-216","si":34},{"s":38,"q":"Two corporations have just completed a merger. The network engineer has been asked to connect the two corporate networks without the expense of leased lines. Which solution would be the most cost effective method of providing a proper and secure connection between the two corporate networks?","o":["Cisco Secure Mobility Clientless SSL VPN","Frame Relay","remote access VPN using IPsec","Cisco AnyConnect Secure Mobility Client with SSL","site-to-site VPN"],"a":[4],"src":"Questions 150-216","si":35},{"s":39,"q":"What is the final operational state that will form between an OSPF DR and a DROTHER once the routers reach convergence?","o":["loading","established","full","two-way"],"a":[2],"src":"Questions 150-216","si":36},{"s":40,"q":"Refer to the exhibit. If the switch reboots and all routers have to re-establish OSPF adjacencies, which routers will become the new DR and BDR?","o":["Router R3 will become the DR and router R1 will become the BDR.","Router R4 will become the DR and router R3 will become the BDR.","Router R1 will become the DR and router R2 will become the BDR.","Router R3 will become the DR and router R2 will become the BDR."],"a":[0],"src":"Questions 150-216","si":37,"e":1},{"s":41,"q":"Which type of server would be used to keep a historical record of messages from monitored network devices?","o":["DNS","print","DHCP","syslog","authentication"],"a":[3],"src":"Questions 150-216","si":38},{"s":42,"q":"When QoS is implemented in a converged network, which two factors can be controlled to improve network performance for real-time traffic? (Choose two.)","o":["packet addressing","delay","jitter","packet routing","link speed"],"a":[1,2],"m":true,"src":"Questions 150-216","si":39},{"s":43,"q":"In which step of gathering symptoms does the network engineer determine if the problem is at the core, distribution, or access layer of the network?","o":["Determine ownership.","Determine the symptoms.","Narrow the scope.","Document the symptoms.","Gather information."],"a":[2],"src":"Questions 150-216","si":40},{"s":44,"q":"What protocol sends periodic advertisements between connected Cisco devices in order to learn device name, IOS version, and the number and type of interfaces?","o":["CDP","SNMP","NTP","LLDP"],"a":[0],"src":"Questions 150-216","si":41},{"s":45,"q":"An administrator is configuring single-area OSPF on a router. One of the networks that must be advertised is 172.20.0.0 255.255.252.0. What wildcard mask would the administrator use in the OSPF network statement?","o":["0.0.15.255","0.0.3.255","0.0.7.255","0.0.1.255"],"a":[1],"src":"Questions 150-216","si":42},{"s":46,"q":"Refer to the exhibit. An administrator configures the following ACL in order to prevent devices on the 192.168.1.0 subnet from accessing the server at 10.1.1.5:\n\naccess-list 100 deny ip 192.168.1.0 0.0.0.255 host 10.1.1.5\naccess-list 100 permit ip any any\nWhere should the administrator place this ACL for the most efficient use of network resources?","o":["inbound on router A Fa0/0","outbound on router B Fa0/0","outbound on router A Fa0/1","inbound on router B Fa0/1"],"a":[0],"src":"Questions 150-216","si":43,"e":1},{"s":47,"q":"A network technician is configuring SNMPv3 and has set a security level of auth . What is the effect of this setting?","o":["authenticates a packet by a string match of the username or community string","authenticates a packet by using either the HMAC with MD5 method or the SHA method","authenticates a packet by using either the HMAC MD5 or 3.HMAC SHA algorithms and encrypts the packet with either the DES, 3DES or AES algorithms","authenticates a packet by using the SHA algorithm only"],"a":[1],"src":"Questions 150-216","si":44},{"s":48,"q":"Refer to the exhibit. The company has provided IP phones to employees on the 192.168.10.0/24 network and the voice traffic will need priority over data traffic. What is the best ACL type and placement to use in this situation?","o":["extended ACL inbound on R1 G0/0","extended ACL outbound on R2 WAN interface towards the internet","extended ACL outbound on R2 S0/0/1","extended ACLs inbound on R1 G0/0 and G0/1"],"a":[0],"src":"Questions 150-216","si":45,"e":1},{"s":49,"q":"Which QoS technique smooths packet output rate?","o":["policing","shaping","weighted random early detection","Integrated Services (IntServ)","marking"],"a":[1],"src":"Questions 150-216","si":46},{"s":50,"q":"Anycompany has decided to reduce its environmental footprint by reducing energy costs, moving to a smaller facility, and promoting telecommuting, what service or technology would support requirement?","o":["Cloud services","Data center","APIC-EM","Cisco ACI"],"a":[0],"src":"Questions 150-216","si":47},{"s":51,"q":"Which step in the link-state routing process is described by a router inserting best paths into the routing table?","o":["declaring a neighbor to be inaccessible","executing the SPF algorithm","load balancing equal-cost paths","choosing the best route"],"a":[3],"src":"Questions 150-216","si":48},{"s":52,"q":"What type of traffic is described as requiring at least 384 Kbps of bandwidth?","o":["voice","data","video"],"a":[2],"src":"Questions 150-216","si":49},{"s":54,"q":"What are two features to consider when creating a named ACL? (Choose two.)","o":["Use alphanumeric characters if needed.","Use special characters, such as ! or * to show the importance of the ACL.","Modify the ACL using a text editor.","Be descriptive when creating the ACL name.","Use a space for ease of reading to separate the name from the description"],"a":[0,3],"m":true,"src":"Questions 150-216","si":50},{"s":55,"q":"Which OSPF database is identical on all converged routers within the same OSPF area?","o":["neighbor","forwarding","link-state","adjacency"],"a":[2],"src":"Questions 150-216","si":51},{"s":56,"q":"Refer to the exhibit. A network administrator has configured a standard ACL to permit only the two LAN networks attached to R1 to access the network that connects to R2 G0/1 interface. When following the best practices, in what location should the standard ACL be applied?","o":["R2 G0/1 inbound","R2 S0/0/1 outbound","R1 S0/0/0 outbound","R2 G0/1 outbound","R2 G0/0 outbound"],"a":[3],"src":"Questions 150-216","si":52,"e":1},{"s":57,"q":"Which virtual resource would be installed on a network server to provide direct access to hardware resources?","o":["VMware Fusion","a management console","a dedicated VLAN","a Type 1 hypervisor"],"a":[3],"src":"Questions 150-216","si":53},{"s":58,"q":"A technician is working on a Layer 2 switch and notices that a\n\n%CDP-4-DUPLEX_MISMATCH\nmessage keeps appearing for port G0/5. What command should the technician issue on the switch to start the troubleshooting process?","o":["show cdp neighbors","show ip interface brief","show interface g0/5","show cdp"],"a":[2],"src":"Questions 150-216","si":54},{"s":59,"q":"Refer to the exhibit. Corporate policy demands that access to the server network be restricted to internal employees only. What is the best ACL type and placement to use in this situation?","o":["extended ACL outbound on R2 S0/0/1","standard ACL outbound on R2 S0/0/0","standard ACL inbound on R2 WAN interface connecting to the internet","extended ACL inbound on R2 S0/0/0"],"a":[0],"src":"Questions 150-216","si":55,"e":1},{"s":60,"q":"An ACL is applied inbound on a router interface. The ACL consists of a single entry:\n\naccess-list 210 permit tcp 172.18.20.0 0.0.0.31 172.18.20.32 0.0.0.31 eq ftp\n\nIf a packet with a source address of 172.18.20.55, a destination address of 172.18.20.3, and a protocol of 21 is received on the interface, is the packet permitted or denied?","o":["permitted","denied"],"a":[1],"src":"Questions 150-216","si":56},{"s":61,"q":"What protocol is a vendor-neutral Layer 2 discovery protocol that must be configured separately to transmit and receive information packets?","o":["SNMP","MPLS","LLDP","NTP"],"a":[2],"src":"Questions 150-216","si":57},{"s":62,"q":"What command would be used as part of configuring NAT or PAT to link the inside local addresses to the pool of addresses available for PAT translation?","o":["ip nat inside source list ACCTNG pool POOL-STAT","ip nat translation timeout 36000","ip nat inside source list 14 pool POOL-STAT overload","ip nat inside source static 172.19.89.13 198.133.219.65"],"a":[2],"src":"Questions 150-216","si":58},{"s":63,"q":"Which three traffic-related factors would influence selecting a particular WAN link type? (Choose three.)","o":["cost of the link","amount of traffic","distance between sites","reliability","security needs","type of traffic"],"a":[1,4,5],"m":true,"src":"Questions 150-216","si":59},{"s":64,"q":"What term describes adding a value to the packet header, as close to the source as possible, so that the packet matches a defined policy?","o":["policing","traffic marking","weighted random early detection (WRED)","traffic shaping","tail drop"],"a":[1],"src":"Questions 150-216","si":60}];
